import React from 'react';
import CardItem from '../CardItem/CardItem';
import { cards } from './Cards.config';
import './Cards.scss';

const Cards = () => {
  return (
    <section className="cards">
      <div className="cards__head">
        <h2>Projects</h2>
        <span>Seven / 2024–26</span>
      </div>

      <div className="cards__items">
        {cards.map((card) => (
          <CardItem
            key={card.label}
            index={card.index}
            text={card.text}
            desc={card.desc}
            tags={card.tags}
            path={'/' + card.label}
            external={card.external}
          />
        ))}
      </div>
    </section>
  );
}

export default Cards;
