import React from 'react';
import { Link } from 'react-router-dom';
import { BASE_PATH } from '../../App';
import './CardItem.css'

const CardItem = ({ index, text, path, desc, tags = [], external }) => {
  const inner = (
    <>
      <span className="proj-index">{index}</span>
      <span className="proj-name">{text}</span>
      <span className="proj-desc">{desc}</span>
      <span className="proj-tags">
        {tags.map((tag) => <span key={tag} className="proj-tag">{tag}</span>)}
      </span>
      <span className="proj-arrow">→</span>
    </>
  );

  // External cards are static files outside the router — use a plain <a>.
  return external
    ? <a className="proj-row" href={BASE_PATH + path}>{inner}</a>
    : <Link className="proj-row" to={path}>{inner}</Link>;
}

export default CardItem;
